mapper.select:
select a.id, a.merchant_name, a.charge_person_name, a.charge_person_phone, a.logo, a.credit_code, a.province_code, a.city_code, a.country_code, a.address, a.staff_count, a.merchant_score, a.state, concat(c1.city_name, c2.city_name, c3.city_name, a.address) as fullAddress from cm_merchant_info a left join city_code c1 on a.province_code = c1.city_id left join city_code c2 on a.city_code = c2.city_id left join city_code c3 on a.country_code = c3.city_id where a.deleted = '0'
and a.id = #{vo.merchantId}
and a.merchant_name like concat('%', #{vo.merchantName}, '%')
and a.verified = #{vo.verified}
